package ir.tahamohamadi.resume.api.admin;
import com.fasterxml.jackson.databind.ObjectMapper; import ir.tahamohamadi.audit.event.*; import ir.tahamohamadi.common.audit.AuthenticatedAuditActor; import ir.tahamohamadi.media.asset.*; import ir.tahamohamadi.resume.*; import org.springframework.data.domain.*; import org.springframework.orm.ObjectOptimisticLockingFailureException; import org.springframework.stereotype.Service; import org.springframework.transaction.annotation.Transactional; import java.time.Instant; import java.util.*;
@Service @Transactional public class AdminResumeDocumentService {private final ResumeDocumentRepository documents;private final MediaAssetRepository media;private final AuditEventRepository audit;private final ObjectMapper mapper;private final AuthenticatedAuditActor actor;public AdminResumeDocumentService(ResumeDocumentRepository documents,MediaAssetRepository media,AuditEventRepository audit,ObjectMapper mapper,AuthenticatedAuditActor actor){this.documents=documents;this.media=media;this.audit=audit;this.mapper=mapper;this.actor=actor;}@Transactional(readOnly=true) public Page<AdminResumeDocumentResponse> list(int page,int size){return documents.findByDeletedAtIsNull(PageRequest.of(page,size,Sort.by(Sort.Order.desc("updatedAt"),Sort.Order.asc("id")))).map(this::response);}@Transactional(readOnly=true) public AdminResumeDocumentResponse get(UUID id){return response(document(id));}public AdminResumeDocumentResponse create(AdminResumeDocumentRequest r){actor.required();if(documents.findByLanguageCodeAndDeletedAtIsNull(r.languageCode()).isPresent())throw new org.springframework.dao.DataIntegrityViolationException("one document per locale");ResumeDocument d=documents.save(ResumeDocument.create(UUID.randomUUID(),r.languageCode(),asset(r.mediaAssetId()),Instant.now()));documents.flush();record("ADMIN_RESUME_DOCUMENT_CREATED",d.getId());return response(d);}public AdminResumeDocumentResponse update(UUID id,AdminResumeDocumentRequest r){ResumeDocument d=document(id);version(d,r.version());if(d.getLanguageCode()!=r.languageCode())throw new IllegalArgumentException("Document locale is immutable");d.update(asset(r.mediaAssetId()),Instant.now());documents.flush();record("ADMIN_RESUME_DOCUMENT_UPDATED",id);return response(d);}public AdminResumeDocumentResponse publish(UUID id,long requested){ResumeDocument d=document(id);version(d,requested);d.publish(Instant.now());documents.flush();record("ADMIN_RESUME_DOCUMENT_PUBLISHED",id);return response(d);}public AdminResumeDocumentResponse archive(UUID id,long requested){ResumeDocument d=document(id);version(d,requested);d.archive(Instant.now());documents.flush();record("ADMIN_RESUME_DOCUMENT_ARCHIVED",id);return response(d);}public void delete(UUID id,long requested){ResumeDocument d=document(id);version(d,requested);d.softDelete(actor.required(),Instant.now());documents.flush();record("ADMIN_RESUME_DOCUMENT_DELETED",id);}private ResumeDocument document(UUID id){return documents.findById(id).filter(d->d.getDeletedAt()==null).orElseThrow(()->new NoSuchElementException("Resume document not found"));}private MediaAsset asset(UUID id){return media.findByIdAndStatusAndDeletedAtIsNull(id,MediaAssetStatus.ACTIVE).orElseThrow(()->new NoSuchElementException("Media asset not found"));}private AdminResumeDocumentResponse response(ResumeDocument d){return new AdminResumeDocumentResponse(d.getId(),d.getLanguageCode(),d.getMediaAsset().getId(),d.getStatus().name(),d.getPublishedAt(),d.getVersion());}private static void version(ResumeDocument d,Long v){if(v==null||d.getVersion()!=v)throw new ObjectOptimisticLockingFailureException(ResumeDocument.class,d.getId());}private void record(String action,UUID id){audit.save(AuditEvent.record(UUID.randomUUID(),Instant.now(),actor.required(),action,"RESUME_DOCUMENT",id,"SUCCESS",null,null,mapper.createObjectNode().put("changedFields","managed")));}}
